#include <bits/stdc++.h>
using namespace std;
struct p{
    int b,c,d,f;
    string e;
};
int main()
{
    int a;
    cin>>a;
    p v[a];
    for(int i=0;i<a;i++)
    {
        cin>>v[i].e>>v[i].b>>v[i].c>>v[i].d;
        v[i].f=v[i].b+v[i].c+v[i].d;
    }
    for(int i=0;i<a-1;i++)
    {
        for(int j=i+1;j<a;j++)
        {
            if((v[i].f+10>=v[j].f)&&(v[i].f-10<=v[j].f))
            {
                if(((v[i].b+5>=v[j].b)&&(v[i].b-5<=v[j].b))&&((v[i].c+5>=v[j].c)&&(v[i].c-5<=v[j].c))&&((v[i].d+5>=v[j].d)&&(v[i].d-5<=v[j].d)))
                {
                    cout<<v[i].e<<' '<<v[j].e<<endl;
                }
            }
        }
    }
    return 0;
}
